<!DOCTYPE html>
<html lang="zh-CN">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0, viewport-fit=cover" />
<title>Q版跳跳闯关</title>
<style>
  html, body {
    margin: 0;
    padding: 0;
    background: linear-gradient(180deg, #aee8ff 0%, #dff7ff 45%, #fff2cc 100%);
    font-family: "Arial", "PingFang SC", "Microsoft YaHei", sans-serif;
    overflow: hidden;
    user-select: none;
    -webkit-user-select: none;
    touch-action: none;
  }
  .wrap {
    min-height: 100vh;
    display: grid;
    place-items: center;
    padding: 8px;
    box-sizing: border-box;
  }
  canvas {
    max-width: 100%;
    height: auto;
    display: block;
    margin: 0 auto;
    background: linear-gradient(180deg, #98ddff 0%, #d6f5ff 55%, #ffe7a9 100%);
    border-radius: 18px;
    box-shadow: 0 12px 40px rgba(0,0,0,.18);
  }
</style>
</head>
<body>
<div class="wrap">
  <canvas id="game"></canvas>
</div>

<script>
const canvas = document.getElementById('game');
const ctx = canvas.getContext('2d');

canvas.width = 360;
canvas.height = 640;

const W = canvas.width;
const H = canvas.height;

const GRAVITY = 0.5;
const MOVE_SPEED = 3.2;
const JUMP_POWER = 10.8;
const MAX_LEVELS = 6;

let keys = {};
let gameState = "menu";
let score = 0;
let totalScore = 0;
let bestScore = Number(localStorage.getItem("cute_jump_best") || 0);
let currentLevel = 1;
let particles = [];
let stars = [];
let clouds = [];
let sparkTimer = 0;
let cameraX = 0;
let messageTimer = 0;
let messageText = "";

function rand(min, max) {
  return Math.random() * (max - min) + min;
}
function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}
function rectsOverlap(a, b) {
  return a.x < b.x + b.w && a.x + a.w > b.x && a.y < b.y + b.h && a.y + a.h > b.y;
}
function roundRect(x, y, w, h, r, fill, stroke) {
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + w, y, x + w, y + h, r);
  ctx.arcTo(x + w, y + h, x, y + h, r);
  ctx.arcTo(x, y + h, x, y, r);
  ctx.arcTo(x, y, x + w, y, r);
  if (fill) ctx.fill();
  if (stroke) ctx.stroke();
}
function drawText(text, x, y, size, color, align="left", strokeColor=null) {
  ctx.font = `bold ${size}px Arial`;
  ctx.textAlign = align;
  ctx.textBaseline = "middle";
  if (strokeColor) {
    ctx.lineWidth = 5;
    ctx.strokeStyle = strokeColor;
    ctx.strokeText(text, x, y);
  }
  ctx.fillStyle = color;
  ctx.fillText(text, x, y);
}

for (let i = 0; i < 30; i++) {
  stars.push({
    x: rand(0, W),
    y: rand(0, H),
    r: rand(1, 3),
    s: rand(0.2, 0.8)
  });
}
for (let i = 0; i < 6; i++) {
  clouds.push({
    x: rand(0, W),
    y: rand(40, 220),
    w: rand(60, 100),
    h: rand(24, 42),
    speed: rand(0.1, 0.35)
  });
}

const player = {
  x: 40,
  y: 0,
  w: 28,
  h: 34,
  vx: 0,
  vy: 0,
  onGround: false,
  coyote: 0,
  jumpBuffer: 0,
  facing: 1,
  alive: true,
  anim: 0
};

let level = null;

function createLevelData(index) {
  const goalX = 920 + (index - 1) * 130;
  const groundY = 560;

  let platforms = [
    {x: -40, y: groundY, w: 180, h: 100, type: "ground"},
    {x: 110, y: 510, w: 60, h: 14, type: "solid"},
    {x: 195, y: 470, w: 62, h: 14, type: index >= 2 ? "bounce" : "solid"},
    {x: 286, y: 430, w: 54, h: 14, type: "solid"},
    {x: 372, y: 392, w: 60, h: 14, type: index >= 3 ? "crumbly" : "solid"},
    {x: 465, y: 350, w: 74, h: 14, type: "solid"},
    {x: 570, y: 312, w: 56, h: 14, type: index >= 2 ? "move" : "solid", baseX: 570, range: 42, dir: 1, speed: 1.1},
    {x: 675, y: 272, w: 66, h: 14, type: "solid"},
    {x: 770, y: 235, w: 72, h: 14, type: index >= 4 ? "move" : "solid", baseX: 770, range: 38, dir: -1, speed: 1.4},
    {x: 880, y: 200, w: 85, h: 14, type: "solid"},
    {x: goalX - 45, y: 160, w: 110, h: 14, type: "goalPlatform"}
  ];

  if (index >= 2) {
    platforms.push({x: 140, y: 410, w: 52, h: 14, type: "solid"});
  }
  if (index >= 3) {
    platforms.push({x: 520, y: 250, w: 52, h: 14, type: "crumbly"});
  }
  if (index >= 4) {
    platforms.push({x: 648, y: 200, w: 54, h: 14, type: "bounce"});
  }
  if (index >= 5) {
    platforms.push({x: 320, y: 300, w: 62, h: 14, type: "move", baseX: 320, range: 56, dir: 1, speed: 1.6});
    platforms.push({x: 910, y: 270, w: 50, h: 14, type: "crumbly"});
  }
  if (index >= 6) {
    platforms.push({x: 430, y: 260, w: 52, h: 14, type: "bounce"});
    platforms.push({x: 1030, y: 225, w: 55, h: 14, type: "move", baseX: 1030, range: 45, dir: 1, speed: 1.8});
  }

  let coins = [];
  platforms.forEach(p => {
    if (p.type !== "ground" && p.type !== "goalPlatform") {
      coins.push({x: p.x + p.w / 2, y: p.y - 18, r: 8, got: false, bob: rand(0, Math.PI * 2)});
    }
  });

  const hazards = [];
  if (index >= 2) hazards.push({x: 170, y: 560, w: 40, h: 18, type: "spike"});
  if (index >= 3) hazards.push({x: 438, y: 560, w: 54, h: 18, type: "spike"});
  if (index >= 4) hazards.push({x: 733, y: 560, w: 50, h: 18, type: "spike"});
  if (index >= 5) hazards.push({x: 980, y: 560, w: 54, h: 18, type: "spike"});
  if (index >= 6) hazards.push({x: 250, y: 560, w: 46, h: 18, type: "spike"});

  return {
    width: goalX + 180,
    height: H,
    start: {x: 36, y: 500},
    goal: {x: goalX, y: 104, w: 32, h: 56},
    platforms,
    coins,
    hazards
  };
}

function loadLevel(index) {
  level = createLevelData(index);
  player.x = level.start.x;
  player.y = level.start.y;
  player.vx = 0;
  player.vy = 0;
  player.onGround = false;
  player.coyote = 0;
  player.jumpBuffer = 0;
  player.alive = true;
  cameraX = 0;
  score = 0;
  messageText = `第 ${index} 关`;
  messageTimer = 80;
}

function startGame() {
  currentLevel = 1;
  totalScore = 0;
  loadLevel(currentLevel);
  gameState = "playing";
}

function nextLevel() {
  totalScore += score;
  currentLevel++;
  if (currentLevel > MAX_LEVELS) {
    if (totalScore > bestScore) {
      bestScore = totalScore;
      localStorage.setItem("cute_jump_best", bestScore);
    }
    gameState = "win";
  } else {
    loadLevel(currentLevel);
  }
}

function restartLevel() {
  loadLevel(currentLevel);
  gameState = "playing";
}

function bounceParticles(x, y, color, count=8) {
  for (let i = 0; i < count; i++) {
    particles.push({
      x, y,
      vx: rand(-2.2, 2.2),
      vy: rand(-3, -0.5),
      life: rand(20, 35),
      maxLife: 35,
      color,
      r: rand(2, 5)
    });
  }
}

function playerDie() {
  bounceParticles(player.x + player.w / 2, player.y + player.h / 2, "#ff6b81", 18);
  player.alive = false;
  gameState = "gameover";
  if (totalScore + score > bestScore) {
    bestScore = totalScore + score;
    localStorage.setItem("cute_jump_best", bestScore);
  }
}

function inputJump() {
  if (gameState === "menu") {
    startGame();
    return;
  }
  if (gameState === "gameover") {
    totalScore = 0;
    restartLevel();
    return;
  }
  if (gameState === "win") {
    startGame();
    return;
  }
  player.jumpBuffer = 10;
}

window.addEventListener("keydown", (e) => {
  keys[e.key.toLowerCase()] = true;
  if (["arrowup", " ", "w"].includes(e.key.toLowerCase())) {
    inputJump();
    e.preventDefault();
  }
  if (gameState !== "playing" && e.key.toLowerCase() === "enter") {
    if (gameState === "menu") startGame();
    else if (gameState === "gameover") { totalScore = 0; restartLevel(); }
    else if (gameState === "win") startGame();
  }
});

window.addEventListener("keyup", (e) => {
  keys[e.key.toLowerCase()] = false;
});

canvas.addEventListener("pointerdown", (e) => {
  const rect = canvas.getBoundingClientRect();
  const px = (e.clientX - rect.left) * (W / rect.width);
  if (gameState !== "playing") {
    inputJump();
    return;
  }
  if (px < W * 0.35) keys["arrowleft"] = true;
  else if (px > W * 0.65) keys["arrowright"] = true;
  inputJump();
});
canvas.addEventListener("pointerup", () => {
  keys["arrowleft"] = false;
  keys["arrowright"] = false;
});
canvas.addEventListener("pointercancel", () => {
  keys["arrowleft"] = false;
  keys["arrowright"] = false;
});

function updatePlatforms() {
  for (const p of level.platforms) {
    if (p.type === "move") {
      p.x += p.speed * p.dir;
      if (p.x > p.baseX + p.range) p.dir = -1;
      if (p.x < p.baseX - p.range) p.dir = 1;
    }
    if (p.type === "crumbly" && p.crackTimer > 0) {
      p.crackTimer--;
      if (p.crackTimer <= 0) p.broken = true;
    }
  }
}

function updatePlayer() {
  if (!player.alive) return;

  player.anim += 0.18;

  let left = keys["arrowleft"] || keys["a"];
  let right = keys["arrowright"] || keys["d"];

  if (left && !right) {
    player.vx = -MOVE_SPEED;
    player.facing = -1;
  } else if (right && !left) {
    player.vx = MOVE_SPEED;
    player.facing = 1;
  } else {
    player.vx *= 0.8;
    if (Math.abs(player.vx) < 0.05) player.vx = 0;
  }

  player.jumpBuffer = Math.max(0, player.jumpBuffer - 1);
  player.coyote = Math.max(0, player.coyote - 1);

  if (player.jumpBuffer > 0 && (player.onGround || player.coyote > 0)) {
    player.vy = -JUMP_POWER;
    player.onGround = false;
    player.coyote = 0;
    player.jumpBuffer = 0;
    bounceParticles(player.x + player.w / 2, player.y + player.h, "#ffffff", 6);
  }

  player.vy += GRAVITY;
  if (player.vy > 12) player.vy = 12;

  const prevX = player.x;
  const prevY = player.y;

  player.x += player.vx;
  player.y += player.vy;

  player.onGround = false;

  for (const p of level.platforms) {
    if (p.broken) continue;

    const platRect = {x: p.x, y: p.y, w: p.w, h: p.h};
    const currRect = {x: player.x, y: player.y, w: player.w, h: player.h};
    if (!rectsOverlap(currRect, platRect)) continue;

    const prevBottom = prevY + player.h;
    const prevTop = prevY;
    const prevRight = prevX + player.w;
    const prevLeft = prevX;

    if (prevBottom <= p.y + 6 && player.vy >= 0) {
      player.y = p.y - player.h;
      player.vy = 0;
      player.onGround = true;
      player.coyote = 8;

      if (p.type === "bounce") {
        player.vy = -15;
        bounceParticles(player.x + player.w / 2, p.y, "#7cf29a", 10);
      }
      if (p.type === "crumbly" && !p.crackTimer) {
        p.crackTimer = 30;
        bounceParticles(player.x + player.w / 2, p.y, "#ffe08a", 7);
      }
      if (p.type === "move") {
        player.x += p.speed * p.dir;
      }
    } else if (prevTop >= p.y + p.h - 4 && player.vy < 0) {
      player.y = p.y + p.h;
      player.vy = 0;
    } else if (prevRight <= p.x + 6 && player.vx > 0) {
      player.x = p.x - player.w;
      player.vx = 0;
    } else if (prevLeft >= p.x + p.w - 6 && player.vx < 0) {
      player.x = p.x + p.w;
      player.vx = 0;
    }
  }

  if (!player.onGround && player.y + player.h < 600) {
    // keep coyote only shortly after leaving ground
  } else if (player.onGround) {
    player.coyote = 8;
  }

  for (const c of level.coins) {
    if (c.got) continue;
    c.bob += 0.09;
    const dx = (player.x + player.w / 2) - c.x;
    const dy = (player.y + player.h / 2) - (c.y + Math.sin(c.bob) * 4);
    if (dx * dx + dy * dy < 18 * 18) {
      c.got = true;
      score += 10;
      bounceParticles(c.x, c.y, "#ffd84d", 12);
      messageText = "+10";
      messageTimer = 20;
    }
  }

  for (const h of level.hazards) {
    if (
      player.x + 6 < h.x + h.w &&
      player.x + player.w - 6 > h.x &&
      player.y + player.h > h.y &&
      player.y + player.h - 10 < h.y + h.h
    ) {
      playerDie();
    }
  }

  const goal = level.goal;
  if (rectsOverlap({x: player.x, y: player.y, w: player.w, h: player.h}, goal)) {
    score += 50;
    bounceParticles(goal.x + goal.w/2, goal.y + goal.h/2, "#ff8fd1", 20);
    nextLevel();
    return;
  }

  if (player.y > H + 80) {
    playerDie();
  }

  cameraX = clamp(player.x - W * 0.35, 0, Math.max(0, level.width - W));
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.x += p.vx;
    p.y += p.vy;
    p.vy += 0.12;
    p.life--;
    if (p.life <= 0) particles.splice(i, 1);
  }
}

function updateBackground() {
  for (const s of stars) {
    s.y += s.s * 0.15;
    if (s.y > H) s.y = -5;
  }
  for (const c of clouds) {
    c.x += c.speed;
    if (c.x > W + 50) c.x = -c.w - 50;
  }
  if (messageTimer > 0) messageTimer--;
  sparkTimer += 0.03;
}

function update() {
  updateBackground();
  if (gameState === "playing") {
    updatePlatforms();
    updatePlayer();
  }
  updateParticles();
}

function drawSky() {
  const g = ctx.createLinearGradient(0, 0, 0, H);
  g.addColorStop(0, "#8edbff");
  g.addColorStop(0.55, "#d9f5ff");
  g.addColorStop(1, "#ffe7a3");
  ctx.fillStyle = g;
  ctx.fillRect(0, 0, W, H);

  ctx.fillStyle = "rgba(255,255,255,0.7)";
  for (const c of clouds) {
    drawCloud(c.x, c.y, c.w, c.h);
  }

  for (const s of stars) {
    ctx.fillStyle = `rgba(255,255,255,${0.45 + Math.sin(sparkTimer + s.x) * 0.2})`;
    ctx.beginPath();
    ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.fillStyle = "#b9f08a";
  ctx.beginPath();
  ctx.moveTo(0, 560);
  ctx.quadraticCurveTo(80, 525, 160, 555);
  ctx.quadraticCurveTo(250, 582, 360, 540);
  ctx.lineTo(360, 640);
  ctx.lineTo(0, 640);
  ctx.closePath();
  ctx.fill();
}

function drawCloud(x, y, w, h) {
  ctx.beginPath();
  ctx.arc(x + w * 0.2, y + h * 0.6, h * 0.28, 0, Math.PI * 2);
  ctx.arc(x + w * 0.42, y + h * 0.43, h * 0.34, 0, Math.PI * 2);
  ctx.arc(x + w * 0.62, y + h * 0.55, h * 0.31, 0, Math.PI * 2);
  ctx.arc(x + w * 0.8, y + h * 0.62, h * 0.22, 0, Math.PI * 2);
  ctx.fill();
}

function drawWorld() {
  ctx.save();
  ctx.translate(-cameraX, 0);

  for (const p of level.platforms) {
    if (p.broken) continue;
    if (p.x + p.w < cameraX - 20 || p.x > cameraX + W + 20) continue;
    drawPlatform(p);
  }

  for (const c of level.coins) {
    if (c.got) continue;
    const y = c.y + Math.sin(c.bob) * 4;
    drawCoin(c.x, y, c.r);
  }

  for (const h of level.hazards) {
    drawSpike(h.x, h.y, h.w, h.h);
  }

  drawGoal(level.goal);
  drawPlayer();

  for (const p of particles) {
    if (p.x < cameraX - 50 || p.x > cameraX + W + 50) continue;
    ctx.globalAlpha = Math.max(0, p.life / p.maxLife);
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
    ctx.fill();
    ctx.globalAlpha = 1;
  }

  ctx.restore();
}

function drawPlatform(p) {
  let top = "#ffcc66", side = "#f3a94f", deco = "#fff2b8";
  if (p.type === "bounce") { top = "#7cf29a"; side = "#3ecf68"; deco = "#c9ffd8"; }
  if (p.type === "move") { top = "#79c7ff"; side = "#4ba5e8"; deco = "#d8f2ff"; }
  if (p.type === "crumbly") { top = "#ffd28f"; side = "#e5a95d"; deco = "#ffe9c5"; }
  if (p.type === "ground") { top = "#8cd96b"; side = "#5bb14f"; deco = "#c8f2a9"; }
  if (p.type === "goalPlatform") { top = "#ff9fd0"; side = "#f06aad"; deco = "#ffd6eb"; }

  ctx.fillStyle = side;
  roundRect(p.x, p.y, p.w, p.h, 8, true);
  ctx.fillStyle = top;
  roundRect(p.x, p.y, p.w, Math.max(10, p.h * 0.55), 8, true);

  ctx.fillStyle = deco;
  for (let i = 0; i < p.w; i += 16) {
    ctx.beginPath();
    ctx.arc(p.x + 8 + i, p.y + 5, 3, 0, Math.PI * 2);
    ctx.fill();
  }

  if (p.type === "crumbly") {
    ctx.strokeStyle = "#b77835";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(p.x + 14, p.y + 4);
    ctx.lineTo(p.x + 23, p.y + 10);
    ctx.lineTo(p.x + 18, p.y + 14);
    ctx.moveTo(p.x + p.w - 20, p.y + 3);
    ctx.lineTo(p.x + p.w - 14, p.y + 9);
    ctx.lineTo(p.x + p.w - 24, p.y + 13);
    ctx.stroke();
  }
  if (p.type === "bounce") {
    ctx.strokeStyle = "#1f9f47";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(p.x + 10, p.y + 10);
    ctx.lineTo(p.x + p.w/2, p.y + 4);
    ctx.lineTo(p.x + p.w - 10, p.y + 10);
    ctx.stroke();
  }
}

function drawCoin(x, y, r) {
  ctx.fillStyle = "#ffd84d";
  ctx.beginPath();
  ctx.arc(x, y, r, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = "#fff3b0";
  ctx.beginPath();
  ctx.arc(x - 2, y - 2, r * 0.45, 0, Math.PI * 2);
  ctx.fill();
  ctx.strokeStyle = "#e0a700";
  ctx.lineWidth = 2;
  ctx.stroke();
}

function drawSpike(x, y, w, h) {
  ctx.fillStyle = "#ff7f96";
  const count = Math.floor(w / 12);
  for (let i = 0; i < count; i++) {
    const sx = x + i * 12;
    ctx.beginPath();
    ctx.moveTo(sx, y + h);
    ctx.lineTo(sx + 6, y);
    ctx.lineTo(sx + 12, y + h);
    ctx.closePath();
    ctx.fill();
  }
}

function drawGoal(g) {
  ctx.fillStyle = "#fff5f9";
  roundRect(g.x, g.y, g.w, g.h, 10, true);
  ctx.fillStyle = "#ff78b6";
  roundRect(g.x + 5, g.y + 6, g.w - 10, g.h - 12, 8, true);

  const fx = g.x + g.w / 2;
  const fy = g.y - 6;
  ctx.strokeStyle = "#8b5a2b";
  ctx.lineWidth = 4;
  ctx.beginPath();
  ctx.moveTo(fx, fy + 10);
  ctx.lineTo(fx, fy - 34);
  ctx.stroke();

  ctx.fillStyle = "#ff4f96";
  ctx.beginPath();
  ctx.moveTo(fx, fy - 32);
  ctx.quadraticCurveTo(fx + 22, fy - 24, fx, fy - 14);
  ctx.quadraticCurveTo(fx + 5, fy - 24, fx, fy - 32);
  ctx.fill();
}

function drawPlayer() {
  const x = player.x;
  const y = player.y;
  const bounce = player.onGround ? Math.sin(player.anim * 2) * 1.5 : 0;

  ctx.save();
  ctx.translate(x + player.w / 2, y + player.h / 2 + bounce);
  ctx.scale(player.facing, 1);

  ctx.fillStyle = "#8b5a2b";
  ctx.beginPath();
  ctx.arc(-8, -13, 6, 0, Math.PI * 2);
  ctx.arc(8, -13, 6, 0, Math.PI * 2);
  ctx.fill();

  ctx.fillStyle = "#ffd6a5";
  ctx.beginPath();
  ctx.roundRect?.(-13, -14, 26, 28, 10);
  if (!ctx.roundRect) roundRect(-13, -14, 26, 28, 10, true);
  else ctx.fill();

  if (!ctx.roundRect) {
  } else {}

  if (ctx.roundRect) {
    // already filled by fillStyle
  }

  ctx.fillStyle = "#ffd6a5";
  roundRect(-13, -14, 26, 28, 10, true);

  ctx.fillStyle = "#fff";
  ctx.beginPath();
  ctx.arc(-5, -4, 4, 0, Math.PI * 2);
  ctx.arc(5, -4, 4, 0, Math.PI * 2);
  ctx.fill();

  ctx.fillStyle = "#333";
  ctx.beginPath();
  ctx.arc(-4 + (player.facing === 1 ? 1 : -1), -3.5, 1.6, 0, Math.PI * 2);
  ctx.arc(6 + (player.facing === 1 ? 1 : -1), -3.5, 1.6, 0, Math.PI * 2);
  ctx.fill();

  ctx.strokeStyle = "#9b5d53";
