    ctx.fillStyle = `rgba(255,255,255,${0.45 + Math.sin(sparkTimer + s.x) * 0.2})`;
    ctx.beginPath();
    ctx.arc(s.x, s.y, s.r, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.fillStyle = "#b9f08a";
  ctx.beginPath();
  ctx.moveTo(0, 560);
