  ctx.quadraticCurveTo(250, 582, 360, 540);
  ctx.lineTo(360, 640);
  ctx.lineTo(0, 640);
  ctx.closePath();
  ctx.fill();
}

function drawCloud(x, y, w, h) {
  ctx.beginPath();
  ctx.arc(x + w * 0.2, y + h * 0.6, h * 0.28, 0, Math.PI * 2);
  ctx.arc(x + w * 0.42, y + h * 0.43, h * 0.34, 0, Math.PI * 2);
  ctx.arc(x + w * 0.62, y + h * 0.55, h * 0.31, 0, Math.PI * 2);
  ctx.arc(x + w * 0.8, y + h * 0.62, h * 0.22, 0, Math.PI * 2);
  ctx.fill();
}

function drawWorld() {
  ctx.save();
  ctx.translate(-cameraX, 0);

  for (const p of level.platforms) {
    if (p.broken) continue;
    if (p.x + p.w < cameraX - 20 || p.x > cameraX + W + 20) continue;
    drawPlatform(p);
  }

  for (const c of level.coins) {
    if (c.got) continue;
    const y = c.y + Math.sin(c.bob) * 4;
    drawCoin(c.x, y, c.r);
  }

  for (const h of level.hazards) {
    drawSpike(h.x, h.y, h.w, h.h);
  }

  drawGoal(level.goal);
  drawPlayer();

  for (const p of particles) {
    if (p.x < cameraX - 50 || p.x > cameraX + W + 50) continue;
    ctx.globalAlpha = Math.max(0, p.life / p.maxLife);
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
    ctx.fill();
    ctx.globalAlpha = 1;
  }

  ctx.restore();
}

function drawPlatform(p) {
  let top = "#ffcc66", side = "#f3a94f", deco = "#fff2b8";
  if (p.type === "bounce") { top = "#7cf29a"; side = "#3ecf68"; deco = "#c9ffd8"; }
  if (p.type === "move") { top = "#79c7ff"; side = "#4ba5e8"; deco = "#d8f2ff"; }
  if (p.type === "crumbly") { top = "#ffd28f"; side = "#e5a95d"; deco = "#ffe9c5"; }
  if (p.type === "ground") { top = "#8cd96b"; side = "#5bb14f"; deco = "#c8f2a9"; }
  if (p.type === "goalPlatform") { top = "#ff9fd0"; side = "#f06aad"; deco = "#ffd6eb"; }

  ctx.fillStyle = side;
  roundRect(p.x, p.y, p.w, p.h, 8, true);
  ctx.fillStyle = top;
  roundRect(p.x, p.y, p.w, Math.max(10, p.h * 0.55), 8, true);

  ctx.fillStyle = deco;
  for (let i = 0; i < p.w; i += 16) {
    ctx.beginPath();
    ctx.arc(p.x + 8 + i, p.y + 5, 3, 0, Math.PI * 2);
    ctx.fill();
  }

  if (p.type === "crumbly") {
    ctx.strokeStyle = "#b77835";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(p.x + 14, p.y + 4);
    ctx.lineTo(p.x + 23, p.y + 10);
    ctx.lineTo(p.x + 18, p.y + 14);
    ctx.moveTo(p.x + p.w - 20, p.y + 3);
    ctx.lineTo(p.x + p.w - 14, p.y + 9);
    ctx.lineTo(p.x + p.w - 24, p.y + 13);
    ctx.stroke();
  }
  if (p.type === "bounce") {
    ctx.strokeStyle = "#1f9f47";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(p.x + 10, p.y + 10);
    ctx.lineTo(p.x + p.w/2, p.y + 4);
    ctx.lineTo(p.x + p.w - 10, p.y + 10);
    ctx.stroke();
  }
}

function drawCoin(x, y, r) {
  ctx.fillStyle = "#ffd84d";
  ctx.beginPath();
  ctx.arc(x, y, r, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = "#fff3b0";
  ctx.beginPath();
  ctx.arc(x - 2, y - 2, r * 0.45, 0, Math.PI * 2);
  ctx.fill();
  ctx.strokeStyle = "#e0a700";
  ctx.lineWidth = 2;
  ctx.stroke();
}

function drawSpike(x, y, w, h) {
  ctx.fillStyle = "#ff7f96";
  const count = Math.floor(w / 12);
  for (let i = 0; i < count; i++) {
    const sx = x + i * 12;
    ctx.beginPath();
    ctx.moveTo(sx, y + h);
    ctx.lineTo(sx + 6, y);
    ctx.lineTo(sx + 12, y + h);
    ctx.closePath();
    ctx.fill();
  }
}

function drawGoal(g) {
  ctx.fillStyle = "#fff5f9";
  roundRect(g.x, g.y, g.w, g.h, 10, true);
  ctx.fillStyle = "#ff78b6";
  roundRect(g.x + 5, g.y + 6, g.w - 10, g.h - 12, 8, true);

  const fx = g.x + g.w / 2;
  const fy = g.y - 6;
  ctx.strokeStyle = "#8b5a2b";
  ctx.lineWidth = 4;
  ctx.beginPath();
  ctx.moveTo(fx, fy + 10);
  ctx.lineTo(fx, fy - 34);
  ctx.stroke();

  ctx.fillStyle = "#ff4f96";
  ctx.beginPath();
  ctx.moveTo(fx, fy - 32);
  ctx.quadraticCurveTo(fx + 22, fy - 24, fx, fy - 14);
  ctx.quadraticCurveTo(fx + 5, fy - 24, fx, fy - 32);
  ctx.fill();
}

function drawPlayer() {
  const x = player.x;
  const y = player.y;
  const bounce = player.onGround ? Math.sin(player.anim * 2) * 1.5 : 0;

  ctx.save();
  ctx.translate(x + player.w / 2, y + player.h / 2 + bounce);
  ctx.scale(player.facing, 1);

  ctx.fillStyle = "#8b5a2b";
  ctx.beginPath();
  ctx.arc(-8, -13, 6, 0, Math.PI * 2);
  ctx.arc(8, -13, 6, 0, Math.PI * 2);
  ctx.fill();

  ctx.fillStyle = "#ffd6a5";
  ctx.beginPath();
  ctx.roundRect?.(-13, -14, 26, 28, 10);
  if (!ctx.roundRect) roundRect(-13, -14, 26, 28, 10, true);
  else ctx.fill();

  if (!ctx.roundRect) {
  } else {}

  if (ctx.roundRect) {
    // already filled by fillStyle
  }

  ctx.fillStyle = "#ffd6a5";
  roundRect(-13, -14, 26, 28, 10, true);

  ctx.fillStyle = "#fff";
  ctx.beginPath();
  ctx.arc(-5, -4, 4, 0, Math.PI * 2);
  ctx.arc(5, -4, 4, 0, Math.PI * 2);
  ctx.fill();

  ctx.fillStyle = "#333";
  ctx.beginPath();
  ctx.arc(-4 + (player.facing === 1 ? 1 : -1), -3.5, 1.6, 0, Math.PI * 2);
  ctx.arc(6 + (player.facing === 1 ? 1 : -1), -3.5, 1.6, 0, Math.PI * 2);
  ctx.fill();

  ctx.strokeStyle = "#9b5d53";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.arc(0, 2, 4, 0.2, Math.PI - 0.2);
  ctx.stroke();

  ctx.fillStyle = "#ff8ca8";
  ctx.beginPath();
  ctx.arc(-9, 2, 2.5, 0, Math.PI * 2);
  ctx.arc(9, 2, 2.5, 0, Math.PI * 2);
  ctx.fill();

  ctx.strokeStyle = "#8b5a2b";
  ctx.lineWidth = 3;
  const leg = player.onGround ? Math.sin(player.anim * 4) * 2 : 0;
  ctx.beginPath();
  ctx.moveTo(-6, 13);
  ctx.lineTo(-6, 19 + leg);
  ctx.moveTo(6, 13);
  ctx.lineTo(6, 19 - leg);
  ctx.moveTo(-12, 2);
  ctx.lineTo(-17, 7 + leg * 0.5);
  ctx.moveTo(12, 2);
  ctx.lineTo(17, 7 - leg * 0.5);
  ctx.stroke();

  ctx.restore();
}

function drawHUD() {
  ctx.fillStyle = "rgba(255,255,255,0.75)";
  roundRect(10, 10, 340, 64, 16, true);

  drawText(`关卡 ${currentLevel}/${MAX_LEVELS}`, 24, 30, 18, "#4b5d7a");
  drawText(`本关 ${score}`, 24, 54, 16, "#ff7a59");
  drawText(`总分 ${totalScore + score}`, 180, 54, 16, "#3a9d5d", "center");
  drawText(`最高 ${bestScore}`, 334, 30, 16, "#7d64d8", "right");

  if (messageTimer > 0) {
    drawText(messageText, W / 2, 96, 26, "#ffffff", "center", "#ff6ea8");
  }

  ctx.fillStyle = "rgba(255,255,255,0.8)";
  roundRect(82, H - 56, 196, 34, 17, true);
  drawText("左/右移动  点击/空格跳跃", W / 2, H - 39, 14, "#4a5b78", "center");
}

function drawMenu() {
  drawSky();
  for (const p of particles) {
    ctx.globalAlpha = Math.max(0, p.life / p.maxLife);
    ctx.fillStyle = p.color;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
    ctx.fill();
    ctx.globalAlpha = 1;
  }

  ctx.fillStyle = "rgba(255,255,255,0.85)";
  roundRect(28, 130, 304, 300, 22, true);

  drawText("Q版跳跳闯关", W/2, 190, 32, "#ff6fa8", "center", "#ffffff");
  drawText("精准跳跃，收集金币，抵达终点旗！", W/2, 235, 16, "#5f6f86", "center");
  drawText("特色平台：弹跳 / 移动 / 易碎", W/2, 265, 16, "#5f6f86", "center");
  drawText("共 6 个关卡，分数越高越厉害", W/2, 295, 16, "#5f6f86", "center");

  ctx.fillStyle = "#ff8ebf";
  roundRect(80, 340, 200, 56, 18, true);
  drawText("点击开始", W/2, 368, 24, "#fff", "center");

  drawText(`最高分：${bestScore}`, W/2, 412, 18, "#7d64d8", "center");
  drawText("操作：左右移动 / 点击或空格跳跃", W/2, 460, 15, "#4b5d7a", "center");

  drawCuteShowcase();
}

function drawCuteShowcase() {
  ctx.save();
  ctx.translate(W/2, 540);
  ctx.fillStyle = "#8cd96b";
  roundRect(-70, 20, 140, 16, 8, true);
  ctx.translate(0, -6);

  ctx.fillStyle = "#8b5a2b";
  ctx.beginPath();
  ctx.arc(-10, -26, 8, 0, Math.PI * 2);
  ctx.arc(10, -26, 8, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = "#ffd6a5";
  roundRect(-16, -28, 32, 34, 12, true);
  ctx.fillStyle = "#fff";
  ctx.beginPath();
  ctx.arc(-6, -16, 5, 0, Math.PI * 2);
  ctx.arc(6, -16, 5, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = "#333";
  ctx.beginPath();
  ctx.arc(-5, -16, 2, 0, Math.PI * 2);
  ctx.arc(7, -16, 2, 0, Math.PI * 2);
  ctx.fill();
  ctx.strokeStyle = "#9b5d53";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.arc(0, -8, 5, 0.2, Math.PI - 0.2);
  ctx.stroke();
  ctx.restore();
}

function drawGameOver() {
  drawSky();
  drawWorld();
  drawHUD();

  ctx.fillStyle = "rgba(0,0,0,0.35)";
  ctx.fillRect(0, 0, W, H);

  ctx.fillStyle = "rgba(255,255,255,0.92)";
  roundRect(38, 200, 284, 200, 22, true);
  drawText("闯关失败", W/2, 245, 30, "#ff6b81", "center");
  drawText(`本次总分：${totalScore + score}`, W/2, 290, 20, "#50607a", "center");
  drawText("点击屏幕重新开始本关", W/2, 333, 18, "#50607a", "center");

  ctx.fillStyle = "#ff8ebf";
  roundRect(88, 355, 184, 40, 18, true);
  drawText("再试一次", W/2, 375, 20, "#fff", "center");
}

function drawWin() {
  drawSky();

  ctx.fillStyle = "rgba(255,255,255,0.9)";
  roundRect(24, 140, 312, 280, 24, true);

  drawText("全部通关！", W/2, 195, 34, "#ff6fa8", "center", "#fff");
  drawText(`最终得分：${totalScore}`, W/2, 250, 24, "#4d607d", "center");
  drawText(`最高分：${bestScore}`, W/2, 286, 20, "#7d64d8", "center");
  drawText("你是跳跃小能手！", W/2, 330, 20, "#3a9d5d", "center");

  ctx.fillStyle = "#8cf0b0";
  roundRect(80, 362, 200, 52, 18, true);
  drawText("再玩一次", W/2, 388, 24, "#fff", "center");

  for (let i = 0; i < 4; i++) {
    drawCoin(90 + i * 60, 455 + Math.sin(sparkTimer * 3 + i) * 6, 12);
  }
}

function render() {
  if (gameState === "menu") drawMenu();
  else if (gameState === "playing") {
    drawSky();
    drawWorld();
    drawHUD();
  } else if (gameState === "gameover") {
    drawGameOver();
  } else if (gameState === "win") {
    drawWin();
  }
}

function loop() {
  update();
  render();
  requestAnimationFrame(loop);
}

for (let i = 0; i < 20; i++) {
  particles.push({
    x: rand(20, W - 20), y: rand(180, 560),
    vx: rand(-0.8, 0.8), vy: rand(-1.5, 0.2),
    life: rand(40, 100), maxLife: 100,
    color: ["#ffd84d", "#ff8ebf", "#9be7ff", "#b6f28a"][i % 4],
    r: rand(2, 4)
  });
}

loop();
</script>
</body>
</html>
